import { describe, expect, it } from 'vitest';
import { truncateWithEllipsis } from './utils.js';

describe('truncateWithEllipsis', () => {
  it('returns the original string unchanged when it already fits', () => {
    expect(truncateWithEllipsis('hello', 10)).toBe('hello');
  });

  it('returns exactly maxLength characters, ending in an ellipsis, when longer than maxLength', () => {
    const result = truncateWithEllipsis('hello world', 8);
    expect(result).toHaveLength(8);
    expect(result.endsWith('\u2026')).toBe(true);
    expect(result.startsWith('hello')).toBe(true);
  });

  it('treats a string exactly at maxLength as fitting (no truncation)', () => {
    expect(truncateWithEllipsis('exact', 5)).toBe('exact');
  });

  it('throws when maxLength is less than 1', () => {
    expect(() => truncateWithEllipsis('x', 0)).toThrow();
  });
});
